// src/Home.js
import React from 'react';
import "../styles/Home.css";
const Home = () => {
  return (
    <section className="home">
  <div className="home-container">
    <div className="home-header">
      <h1>
        Need a Custom Project for School or College?
        <span className="highlight">ProjectDuniya is Here to Help!</span>
      </h1>
      <p>
        We provide 100% customized academic and technical projects tailored to student needs —
        whether it’s a science model, coding task, research paper, or presentation.
      </p>
      <div className="home-buttons">
        <a href="#services" className="btn primary-btn">Explore Services</a>
        <a href="https://wa.me/918391808784" target="_blank" rel="noopener noreferrer" className="btn secondary-btn">Chat on WhatsApp</a>
      </div>
    </div>

    <div className="home-image">
      <img src="/path-to-your-illustration.png" alt="Online Learning" />
    </div>
  </div>
</section>

  );
};

export default Home;
